def calculate_retention(users, period_days):
    active = [u for u in users if u.last_login_days_ago <= period_days]
    return len(active) / len(users) if users else 0

def segment_users(users, criteria):
    segments = {}
    for user in users:
        key = criteria(user)
        segments.setdefault(key, []).append(user)
    return segments

def detect_churn_risk(user):
    if user.last_login_days_ago > 30 and user.session_count < 3:
        return 'high'
    elif user.last_login_days_ago > 14:
        return 'medium'
    return 'low'
